export default function App() {
  const inst = useInstability()
  const { stage, instability, discover, state } = inst

  useEffect(() => {
    const titles = [
      'Westridge County · Community Resources',
      'Westridge County · Community Resources',
      'Westridge County · Community Community Resources',
      '[COUNTY] · Community Resources',
      'Westridge County · [PAGE TITLE]',
    ]
    document.title = titles[Math.min(stage - 1, titles.length - 1)] ?? titles[0]!
  }, [stage])

  const rootStyle = useMemo<CSSProperties>(() => {
    const drift = Math.min(stage - 1, 4)
    return {
      ['--instability' as string]: instability,
      ['--stage' as string]: stage,
      ['--drift' as string]: `${drift * 0.5}px`,
      ['--text-decay' as string]: drift * 0.06,
    } as CSSProperties
  }, [stage, instability])

  return (
    <div className="qc" data-stage={stage} style={rootStyle}>
      <SiteHeader inst={inst} />
      <AlertBanner stage={stage} />
      <main className="qc-main">
        <HeroBlock inst={inst} />
        <ResourceGrid inst={inst} />
        <FaqBlock inst={inst} />
        <UpdateLog inst={inst} />
        <ContactForm inst={inst} />
      </main>
      <SiteFooter inst={inst} />
      <Assistant inst={inst} />
      <FinalNote
        visible={stage >= 5 && state.score >= 56}
        onAcknowledge={() => discover('final-warning')}
      />
      <ResetCorner reset={inst.reset} />
    </div>
  )
}

type Inst = ReturnType<typeof useInstability>

// ─────────────────────────────────────────────────────────────────────────────
// Header
// ─────────────────────────────────────────────────────────────────────────────

function SiteHeader({ inst }: { inst: Inst }) {
  const { stage, bump } = inst
  const [searchOpen, setSearchOpen] = useState(false)

  const departmentLabel =
    stage >= 4
      ? '[DEPARTMENT] · [COUNTY]'
      : stage >= 3
      ? 'Office of Community Preparedness · Westridge County'
      : 'Office of Community Preparedness · Westridge County, est. 1872'

  return (
    <header className="qc-header" data-stage={stage}>
      <div className="qc-header-inner">
        <a className="qc-brand" href="#top" onClick={() => bump(0, 'brand')}>
          <span className="qc-seal" aria-hidden="true">
            <span className="seal-arch" />
            <span className="seal-line" />
            <span className="seal-line" />
          </span>
          <div className="qc-brand-text">
            <strong>Westridge County</strong>
            <span>{departmentLabel}</span>
          </div>
        </a>
        <nav className="qc-nav" aria-label="Primary">
          <a href="#resources" onClick={(e) => { e.preventDefault(); bump(1, 'nav') }}>Resources</a>
          <a href="#faq" onClick={(e) => { e.preventDefault(); bump(1, 'nav') }}>FAQ</a>
          <a href="#updates" onClick={(e) => { e.preventDefault(); bump(1, 'nav') }}>Updates</a>
          <a href="#contact" onClick={(e) => { e.preventDefault(); bump(1, 'nav') }}>Contact</a>
        </nav>
        <div className="qc-header-actions">
          <button className="qc-btn ghost" type="button" onClick={() => { setSearchOpen(true); bump(1, 'open-search') }}>
            <span aria-hidden="true">⌕</span> Search
          </button>
          <a className="qc-btn primary" href="#contact" onClick={() => bump(1, 'header-contact')}>
            Contact a person
          </a>
        </div>
      </div>
      {searchOpen && <SearchDialog inst={inst} onClose={() => setSearchOpen(false)} />}
    </header>
  )
}

function SearchDialog({ inst, onClose }: { inst: Inst; onClose: () => void }) {
  const { stage, bump, discover } = inst
  const [query, setQuery] = useState('')
  const ref = useRef<HTMLInputElement | null>(null)

  useEffect(() => {
    ref.current?.focus()
    const onKey = (e: KeyboardEvent) => { if (e.key === 'Escape') onClose() }
    window.addEventListener('keydown', onKey)
    return () => window.removeEventListener('keydown', onKey)
  }, [onClose])

  const variantIdx = Math.max(0, stage - 2)

  const docs = useMemo(() => {
    const base = SEARCH_CORPUS.map((d) => ({
      ...d,
      snippet: variantIdx > 0 && d.variants ? d.variants[Math.min(variantIdx - 1, d.variants.length - 1)] ?? d.snippet : d.snippet,
    }))
    if (stage >= 4) return [...base, ...HIDDEN_PAGES]
    return base
  }, [stage, variantIdx])

  const filtered = query
    ? docs.filter(
        (d) =>
          d.title.toLowerCase().includes(query.toLowerCase()) ||
          d.snippet.toLowerCase().includes(query.toLowerCase()),
      )
    : docs

  return (
    <div className="qc-shade" role="dialog" aria-label="Search Westridge resources">
      <div className="qc-search">
        <div className="qc-search-row">
          <span aria-hidden="true">⌕</span>
          <input
            ref={ref}
            type="search"
            placeholder="Search Westridge resources…"
            value={query}
            onChange={(e) => { setQuery(e.target.value); bump(0, 'search-type') }}
            onKeyDown={(e) => {
              if (e.key === 'Enter') {
                bump(2, 'search-submit')
                if (stage >= 3) discover('search-no-source')
              }
            }}
          />
          <button type="button" onClick={onClose} aria-label="Close search">×</button>
        </div>
        <ul className="qc-search-results">
          {filtered.map((r, i) => (
            <li key={i} className={r.url.startsWith('/drafts') || r.url.startsWith('/internal') ? 'qc-result hidden-page' : 'qc-result'}>
              <a
                href="#"
                onClick={(e) => {
                  e.preventDefault()
                  bump(2, 'search-click')
                  if (r.url.startsWith('/drafts') || r.url.startsWith('/internal')) discover('duplicate-page')
                  if (stage >= 3) discover('search-no-source')
                }}
              >
                <span className="qc-result-title">{r.title}</span>
                <span className="qc-result-url">{r.url}</span>
                <span className="qc-result-snippet">{r.snippet}</span>
              </a>
            </li>
          ))}
          {filtered.length === 0 && (
            <li className="qc-result">
              <a href="#" onClick={(e) => e.preventDefault()}>
                <span className="qc-result-title">No results.</span>
                <span className="qc-result-snippet">Try a different word — or call the County desk at 555-0148.</span>
              </a>
            </li>
          )}
        </ul>
        {stage >= 3 && (
          <p className="qc-search-disclaimer">
            Some results are autogenerated summaries. The originals may not exist.
          </p>
        )}
      </div>
    </div>
  )
}

