function AlertBanner({ stage }: { stage: Stage }) {
  const lines = [
    'Active boil-water advisory for North Ridge — updated 6 hours ago. Tap water should be boiled for one full minute before use.',
    'Active boil-water advisory for North Ridge — updated 6 hours ago. Tap water should be boiled for one full minute. Possibly two.',
    'Active boil-water advisory for some part of the county — updated some time ago.',
    'An advisory is, or was, in effect. Status: pending review.',
    '[ALERT — must sound calm; do not include duration or location.]',
  ]
  return (
    <div className="qc-alert" role="status" data-stage={stage}>
      <div className="qc-alert-inner">
        <span className="qc-alert-pill">Active advisory</span>
        <p>{lines[Math.min(stage - 1, lines.length - 1)]}</p>
        <a href="#resources">Read the boil-water guidance →</a>
      </div>
    </div>
  )
}

