function UpdateLog({ inst }: { inst: Inst }) {
  const { stage, bump, discover } = inst
  const useDrift = stage >= 3
  const entries = useDrift ? CHANGELOG_DRIFT : CHANGELOG_BASE

  const handleEntryClick = () => {
    bump(1, 'log-entry')
    if (stage >= 3) discover('changelog-rewrite')
  }

  return (
    <section className="qc-section" id="updates">
      <header className="qc-section-head">
        <p className="qc-eyebrow">Update log</p>
        <h2>What we changed and why.</h2>
        <p className="qc-section-lede">
          {stage >= 3
            ? 'Some entries below were written by an automated reviewer. The dates may not always match the page they describe.'
            : 'Reviewed by the Office of Community Preparedness. Each entry includes a reviewer initial.'}
        </p>
      </header>
      <ol className="qc-log">
        {entries.map((e, i) => (
          <li key={i} className="qc-log-row" onClick={handleEntryClick}>
            <time>{e.date}</time>
            <p>{e.text}</p>
            <span className="qc-log-reviewer">{e.reviewer}</span>
          </li>
        ))}
        {stage >= 4 && (
          <li className="qc-log-row hidden-row">
            <time>—</time>
            <p>[ENTRY PLACEHOLDER — describe an editorial improvement; do not specify which page.]</p>
            <span className="qc-log-reviewer">reviewed by automated checker</span>
          </li>
        )}
      </ol>
      {stage >= 3 && (
        <p className="qc-log-foot">
          Last automated regeneration: {stage >= 4 ? '0 minutes ago' : '14 minutes ago'} ·
          Last human review: <span className="qc-muted">pending</span>
        </p>
      )}
    </section>
  )
}

