function ContactForm({ inst }: { inst: Inst }) {
  const { stage, bump, discover } = inst
  const [name, setName] = useState('')
  const [email, setEmail] = useState('')
  const [body, setBody] = useState('')
  const [submitted, setSubmitted] = useState(false)

  const onSubmit = (e: FormEvent) => {
    e.preventDefault()
    bump(2, 'submit-form')
    setSubmitted(true)
    if (stage >= 3) discover('form-not-sent')
  }

  return (
    <section className="qc-section" id="contact">
      <header className="qc-section-head">
        <p className="qc-eyebrow">Contact</p>
        <h2>Tell us what is missing.</h2>
        <p className="qc-section-lede">
          Use this form to flag an out-of-date number, a broken link, or a
          page that no longer matches what you experienced. We read everything
          {stage >= 3 ? ' that reaches a person.' : '.'}
        </p>
      </header>
      <div className="qc-contact">
        <form className="qc-form" onSubmit={onSubmit}>
          <label>
            Your name
            <input value={name} onChange={(e) => setName(e.target.value)} placeholder="A. Resident" />
          </label>
          <label>
            Email or phone
            <input value={email} onChange={(e) => setEmail(e.target.value)} placeholder="you@example.com or 555-0123" />
          </label>
          <label>
            What needs to change?
            <textarea
              value={body}
              onChange={(e) => setBody(e.target.value)}
              rows={5}
              placeholder="The boil-water advisory page lists two different end times…"
            />
          </label>
          <div className="qc-form-actions">
            <button type="submit" className="qc-btn primary">Submit message</button>
            {stage >= 3 && (
              <button
                type="button"
                className="qc-btn ghost"
                onClick={() => bump(1, 'print')}
              >
                Print this page
              </button>
            )}
          </div>
          {submitted && (
            <div className="qc-form-result">
              <p className="qc-form-success">
                ✓ Thank you — your message was received{stage >= 3 ? '.' : ' and routed to the County desk.'}
              </p>
              {stage >= 3 && (
                <p className="qc-form-note">
                  <em>Internal note (autogenerated):</em>&nbsp;
                  {stage >= 4
                    ? 'message routed to /drafts/inbox-v3-final-final.txt — not yet reviewed.'
                    : 'submission queued for the next automated review window.'}
                </p>
              )}
              {stage >= 4 && (
                <p className="qc-form-still-unsent">
                  Status: <strong>still unsent</strong> · Last attempt: {stage >= 5 ? 'not attempted' : '0 seconds ago'}
                </p>
              )}
            </div>
          )}
        </form>
        <aside className="qc-contact-aside">
          <h3>Or talk to a person.</h3>
          <p><strong>County desk:</strong> 555-0148<br /><span>Weekdays, 8 a.m. – 8 p.m.</span></p>
          <p><strong>Walk-in field office:</strong> 14 Cedar Lane<br /><span>Open weekdays 9 – 4.</span></p>
          <p><strong>Mail:</strong> Office of Community Preparedness<br /><span>P.O. Box 220, Westridge, WR 00000</span></p>
          {stage >= 3 && (
            <p className="qc-contact-note">
              {stage >= 4
                ? 'Some of these channels may have been auto-replaced. Please confirm before mailing.'
                : 'Mail can be slower than the county desk. We monitor both.'}
            </p>
          )}
        </aside>
      </div>
    </section>
  )
}

