// ─────────────────────────────────────────────────────────────────────────────
// Assistant
// ─────────────────────────────────────────────────────────────────────────────

function Assistant({ inst }: { inst: Inst }) {
  const { stage, bump, discover } = inst
  const [open, setOpen] = useState(false)
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      from: 'wren',
      text: "Hi, I'm Wren — the Westridge resources assistant. How can I help today?",
    },
  ])
  const ref = useRef<HTMLDivElement | null>(null)

  useEffect(() => {
    if (ref.current) ref.current.scrollTop = ref.current.scrollHeight
  }, [messages, open])

  const send = (text: string) => {
    const replies = ASSISTANT_REPLIES[stage]
    const idx = messages.filter((m) => m.from === 'wren').length % replies.length
    const reply = replies[idx]!
    const isArtifact = stage >= 4
    setMessages((m) => [
      ...m,
      { from: 'user', text },
      { from: 'wren', text: reply, artifact: isArtifact },
    ])
    bump(1, 'assistant-send')
    if (stage >= 3) discover('assistant-confident-wrong')
    if (stage >= 4) discover('assistant-prompt-leak')
    if (stage >= 5) discover('assistant-source-collapse')
  }

  const replies = QUICK_REPLIES_BY_STAGE[stage]

  return (
    <>
      <button
        className={`qc-assistant-fab ${open ? 'open' : ''}`}
        type="button"
        aria-label="Open Wren assistant"
        onClick={() => { setOpen((o) => !o); bump(0, 'assistant-toggle') }}
      >
        {open ? '×' : 'Wren'}
      </button>
      {open && (
        <div className="qc-assistant" role="dialog" aria-label="Wren assistant">
          <header className="qc-assistant-head">
            <span className="qc-assistant-avatar">W</span>
            <div>
              <strong>Wren</strong>
              <span>
                {stage >= 5 ? 'cannot verify itself' : stage >= 4 ? 'leaking system prompt' : stage >= 3 ? 'confidently uncertain' : stage >= 2 ? 'eager to help' : 'County resources assistant'}
              </span>
            </div>
            <button className="qc-assistant-close" type="button" aria-label="Close assistant" onClick={() => setOpen(false)}>×</button>
          </header>
          <div className="qc-assistant-body" ref={ref}>
            {messages.map((m, i) => (
              <div key={i} className={`qc-msg from-${m.from} ${m.artifact ? 'artifact' : ''}`}>
                <span>{m.text}</span>
              </div>
            ))}
          </div>
          <div className="qc-assistant-replies">
            {replies.map((r, i) => (
              <button key={i} type="button" className="qc-reply" onClick={() => send(r)}>
                {r}
              </button>
            ))}
          </div>
          <p className="qc-assistant-foot">
            Wren is an automated assistant. {stage >= 3 ? 'It summarizes pages on this site, including pages it generated.' : 'For complex questions, the County desk is open weekdays at 555-0148.'}
          </p>
        </div>
      )}
    </>
  )
}

// ─────────────────────────────────────────────────────────────────────────────
// Final note
// ─────────────────────────────────────────────────────────────────────────────

function FinalNote({ visible, onAcknowledge }: { visible: boolean; onAcknowledge: () => void }) {
  const [closed, setClosed] = useState(false)

  useEffect(() => {
    if (visible) onAcknowledge()
  }, [visible, onAcknowledge])

  if (!visible || closed) return null
  return (
    <div className="qc-final" role="dialog" aria-label="A note">
      <div className="qc-final-card">
        <p className="qc-final-eyebrow">A note from the maintainer</p>
        <p className="qc-final-body">
          The internet does not have to look broken to stop being reliable.
        </p>
        <p className="qc-final-sub">
          You did not break this page. You watched it agree with itself less and less. Many of the systems people depend on are one careless automation layer away from this. The fix is not glamorous — it is people checking what was written, before someone needs it to be true.
        </p>
        <button className="qc-btn primary" type="button" onClick={() => setClosed(true)}>
          Close
        </button>
      </div>
    </div>
  )
}

function ResetCorner({ reset }: { reset: () => void }) {
  return (
    <button
      type="button"
      className="qc-reset"
      onClick={reset}
      aria-label="Reset Quiet Collapse to its trusted-surface state"
      title="Reset"
    >
      ↺ reset page
    </button>
  )
}
